import React from "react";
import { useNavigate } from "react-router-dom";
import { authService } from "../services";
import "../styles/Navbar.css";

const Navbar = () => {
  const user = authService.getCurrentUser();
  const navigate = useNavigate();
  const isAuthenticated = authService.isAuthenticated();
  const isAdmin = user?.role === "admin";

  const handleLogout = () => {
    authService.logout();
    // Redirect to appropriate login based on user role
    if (isAdmin) {
      navigate("/admin/login");
    } else {
      navigate("/user/login");
    }
  };

  const handleDashboardClick = () => {
    // Redirect to appropriate dashboard based on user role
    if (isAdmin) {
      navigate("/admin/dashboard");
    } else {
      navigate("/user/dashboard");
    }
  };

  return (
    <nav className="navbar">
      <div className="navbar-container">
        <div className="navbar-brand">
          <h1>Load Management</h1>
        </div>
        <div className="navbar-links">
          {isAuthenticated ? (
            <>
              <span className="user-info">
                Welcome, {user?.name} ({isAdmin ? "Admin" : "User"})
              </span>
              <button onClick={handleDashboardClick} className="nav-link">
                Dashboard
              </button>
              <button onClick={() => navigate("/loads")} className="nav-link">
                Loads
              </button>
              <button
                onClick={() => navigate("/create-load")}
                className="nav-link"
              >
                Create Load
              </button>
              <button onClick={handleLogout} className="nav-link logout">
                Logout
              </button>
            </>
          ) : (
            <>
              <button
                onClick={() => navigate("/user/login")}
                className="nav-link"
              >
                User Login
              </button>
              <button
                onClick={() => navigate("/admin/login")}
                className="nav-link"
              >
                Admin Login
              </button>
              <button
                onClick={() => navigate("/user/register")}
                className="nav-link"
              >
                User Register
              </button>
              <button
                onClick={() => navigate("/admin/register")}
                className="nav-link"
              >
                Admin Register
              </button>
            </>
          )}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
